using System.ComponentModel.DataAnnotations; using System.Reflection;  namespace BulkRequest.Connection {     public enum ConnectionMode     {         [Display(Name = "")]         None,         [Display(Name = "База данных")]         Single,         [Display(Name = "Несколько баз данных")]         SingleMany,         [Display(Name = "Сервер")]         Server,         [Display(Name = "Несколько серверов")]         ServerMany,         [Display(Name = "Группа серверов")]         Bulk     }      public record ConnectionModeItem(         string Name,         ConnectionMode Mode);      public static class ConnectionModeItemCollection     {         public static List<ConnectionModeItem> GetConnectionModes()         {             List<ConnectionModeItem> connectionModes = [];              foreach (var mode in Enum.GetValues<ConnectionMode>())             {                 string? modeName = typeof(ConnectionMode)                     .GetField(mode.ToString())?                     .GetCustomAttribute<DisplayAttribute>()?.GetName();                 ConnectionModeItem newModeItem = new(                     modeName ?? mode.ToString(),                     mode);                 connectionModes.Add(newModeItem);             }              return connectionModes;         }     } }